1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteOptions {
13	  followUp?: boolean;
14	}
15	
16	export interface QuoteResult {
17	  basePremium: number;
18	  premium: number;
19	  items: Item[];
20	  remainingCap?: number;
21	}
22	
23	const basePremiumByType: Record<string, number> = {
24	  amulet: 60,
25	  sword: 100,
26	  staff: 80,
27	  potion: 40,
28	  rune: 25,
29	  moonstone: 25,
30	};
31	
32	const PROCESSING_FEE = 5;
33	const BLOCK_OF_THREE_PREMIUM = 60;
34	const LOYALTY_DISCOUNT_RATE = 0.2;
35	const FIRST_INSURANCE_RATE = 0.1;
36	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
37	const CURSE_SURCHARGE_RATE = 0.5;
38	const HIGH_ENCHANTMENT_THRESHOLD = 5;
39	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
40	
41	function enchantmentLevel(item: Item): number {
42	  return item.enchantment ?? 0;
43	}
44	
45	function surchargeRateFor(item: Item): number {
46	  let rate = 0;
47	  if (item.cursed) rate += CURSE_SURCHARGE_RATE;
48	  if (enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD) rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
49	  return rate;
50	}
51	
52	function surchargeFor(item: Item): number {
53	  return basePremiumByType[item.type] * surchargeRateFor(item);
54	}
55	
56	function premiumForTypeBlock(type: string, count: number): number {
57	  if (count === 3) return BLOCK_OF_THREE_PREMIUM;
58	  return count * basePremiumByType[type];
59	}
60	
61	function validateInsurableTypes(items: Item[]): void {
62	  for (const item of items) {
63	    if (!(item.type in basePremiumByType)) {
64	      throw new Error(`Unknown item type: ${item.type}`);
65	    }
66	  }
67	}
68	
69	export function quote(
70	  customer: Customer,
71	  items: Item[],
72	  options: QuoteOptions = {},
73	): QuoteResult {
74	  validateInsurableTypes(items);
75	  const countByType = items.reduce<Record<string, number>>((counts, item) => {
76	    counts[item.type] = (counts[item.type] ?? 0) + 1;
77	    return counts;
78	  }, {});
79	  const baseWithoutSurcharges = Object.entries(countByType).reduce(
80	    (sum, [type, count]) => sum + premiumForTypeBlock(type, count),
81	    0,
82	  );
83	  const surcharges = items.reduce((sum, item) => sum + surchargeFor(item), 0);
84	  const basePremium = baseWithoutSurcharges + surcharges;
85	
86	  let premium = basePremium;
87	  if (customer.yearsWithMHPCO >= 2) premium -= baseWithoutSurcharges * LOYALTY_DISCOUNT_RATE;
88	  premium += baseWithoutSurcharges * FIRST_INSURANCE_RATE;
89	  if (options.followUp) premium -= baseWithoutSurcharges * FOLLOW_UP_DISCOUNT_RATE;
90	  premium = Math.ceil(premium + PROCESSING_FEE);
91	
92	  return { basePremium, premium, items };
93	}
94	
95	export interface Damage {
96	  itemType: string;
97	  amount: number;
98	}
99	
100	export interface Incident {
101	  cause: string;
102	  damages: Damage[];
103	}
104	
105	export interface ClaimResult {
106	  payout: number;
107	  remainingCap: number;
108	}
109	
110	const insuranceValueByType: Record<string, number> = {
111	  sword: 1000,
112	  amulet: 600,
113	  staff: 800,
114	  potion: 400,
115	  rune: 250,
116	  moonstone: 250,
117	};
118	
119	const CAP_MULTIPLIER = 2;
120	const DEDUCTIBLE = 100;
121	const HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
122	const HALF_REIMBURSEMENT_RATE = 0.5;
123	
124	function totalInsuranceValue(policy: QuoteResult): number {
125	  return policy.items.reduce((sum, item) => sum + insuranceValueByType[item.type], 0);
126	}
127	
128	function remainingCapFor(policy: QuoteResult): number {
129	  return policy.remainingCap ?? CAP_MULTIPLIER * totalInsuranceValue(policy);
130	}
131	
132	function reimbursedAmount(damage: Damage, policy: QuoteResult): number {
133	  const damagedItem = policy.items.find((item) => item.type === damage.itemType);
134	  if (damagedItem === undefined) {
135	    throw new Error(`Claimed item not in policy: ${damage.itemType}`);
136	  }
137	  const halfReimbursementApplies =
138	    enchantmentLevel(damagedItem) >= HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD;
139	  return halfReimbursementApplies
140	    ? damage.amount * HALF_REIMBURSEMENT_RATE
141	    : damage.amount;
142	}
143	
144	function payoutForDamage(damage: Damage, policy: QuoteResult): number {
145	  return reimbursedAmount(damage, policy) - DEDUCTIBLE;
146	}
147	
148	export function claim(policy: QuoteResult, incident: Incident): ClaimResult {
149	  const totalPayout = incident.damages.reduce(
150	    (total, damage) => total + payoutForDamage(damage, policy),
151	    0,
152	  );
153	  const desiredPayout = Math.floor(totalPayout);
154	  const remainingCapBefore = remainingCapFor(policy);
155	  const payout = Math.min(desiredPayout, remainingCapBefore);
156	  const remainingCap = remainingCapBefore - payout;
157	  policy.remainingCap = remainingCap;
158	  return { payout, remainingCap };
159	}
